def outline_policy(self, flow, state, context, tools):
    if not flow.slots['source'].check_if_filled():
        self.ambiguity.declare('partial', metadata={'missing_entity': 'post'})
        return DisplayFrame(flow.name())

    depth_slot = flow.slots['depth']
    depth = int(depth_slot.level) if depth_slot.check_if_filled() else 2

    if flow.slots['sections'].check_if_filled():
        flow.stage = 'direct'
        post_id = state.active_post
        text, tool_log = self.llm_execute(flow, state, context, tools,
            extra_resolved={'depth': depth})
        saved, _ = self.engineer.tool_succeeded(tool_log, 'generate_outline')
        if not text or not saved:
            return self.error_frame(flow, 'failed_to_save',
                thoughts='LLM failed to generate outline.',
                failed_tool='generate_outline')
        for step in flow.slots['sections'].steps:
            flow.slots['sections'].mark_as_complete(step['name'])
        flow.status = 'Completed'
        frame = DisplayFrame(flow.name(), thoughts=text,
            metadata={'stage': 'direct', 'post_id': post_id})
        frame.add_block({'type': 'card', 'data': self._read_post_content(post_id, tools)})
        return frame

    if flow.slots['topic'].check_if_filled():
        flow.stage = 'propose'
        if flow.slots['proposals'].check_if_filled():
            chosen = flow.slots['proposals'].values[0]
            for sec in chosen:
                flow.slots['sections'].add_one(sec)
            return self.outline_policy(flow, state, context, tools)
        return self._propose_outline(flow, state, context, tools, depth=depth)

    convo_history = context.compile_history(look_back=3)
    prompt = f'{convo_history}\n\nExtract the topic the user wants to outline. Reply with JSON: {{"topic": "..."}}.'
    parsed = self.engineer.apply_guardrails(self.engineer(prompt, 'fill_slots'))
    flow.fill_slots_by_label({'topic': parsed and parsed.get('topic')})

    if flow.slots['topic'].filled:
        flow.stage = 'propose'
        return self._propose_outline(flow, state, context, tools, depth=depth)

    flow.stage = 'error'
    self.ambiguity.declare('specific', metadata={'missing_slot': 'topic'})
    return DisplayFrame(flow.name())

def _propose_outline(self, flow, state, context, tools, depth:int=2):
    # Strip outline-persistence tools from the skill's tool registry in propose
    # mode; the skill must emit three options as text, not save.
    raw, tool_log = self.llm_execute(flow, state, context, tools,
        extra_resolved={'depth': depth},
        exclude_tools=('generate_outline', 'generate_section'))
    options = self.engineer.apply_guardrails(raw, format='outline_options')
    if not options or len(options) != 3:
        return self.error_frame(flow, 'parse_failure',
            thoughts='Outline propose did not return 3 options.',
            code=raw)
    for opt in options:
        flow.slots['proposals'].add_one(opt)
    frame = DisplayFrame(flow.name(),
        metadata={'stage': 'propose', 'option_count': len(options)})
    frame.add_block({'type': 'selection', 'data': {'options': options}})
    return frame
